class Move:
    def __init__(self, start, end, captures=None):
        self.start = start
        self.end = end
        self.captures = captures if captures else []

    def apply(self, board):
        start_pos = self.start
        end_pos = self.end
        piece = board.get_piece(start_pos)
        if piece:
            piece.move(end_pos)
            board.place_piece(end_pos, piece)
            for capture in self.captures:
                board.remove_piece(capture)
